import{_ as i,C as n,o,c,a3 as t,b as l,w as a,a as d,E as s,a4 as u}from"./chunks/framework.aYYe0dfI.js";const x=JSON.parse('{"title":"Module agent:tools","description":"The agent:tools module defines the tool system used by the agent to interact with and analyze C++ codebases. It owns a collection of concrete tool implementations—such as listing files, searching symbols, retrieving namespace contents, getting module or dependency information, and managing project guides—all registered in a static registry. The public interface centers on build_tool_definitions to populate the registry and dispatch_tool_call to execute a named tool with JSON arguments, returning either a string result or a ToolError. Supporting public types include ToolError, ToolContext (carrying project root, model, and output root), and the ToolResultCache for memoizing results. The module also exposes helper functions like extract_string_arg for argument validation and normalization utilities for guide filenames.","frontmatter":{"title":"Module agent:tools","description":"The agent:tools module defines the tool system used by the agent to interact with and analyze C++ codebases. It owns a collection of concrete tool implementations—such as listing files, searching symbols, retrieving namespace contents, getting module or dependency information, and managing project guides—all registered in a static registry. The public interface centers on build_tool_definitions to populate the registry and dispatch_tool_call to execute a named tool with JSON arguments, returning either a string result or a ToolError. Supporting public types include ToolError, ToolContext (carrying project root, model, and output root), and the ToolResultCache for memoizing results. The module also exposes helper functions like extract_string_arg for argument validation and normalization utilities for guide filenames.","layout":"doc","template":"doc"},"headers":[],"relativePath":"clore/modules/agent/tools.md","filePath":"en/clore/modules/agent/tools.md"}'),h={name:"clore/modules/agent/tools.md"};function p(m,e,g,f,b,_){const r=n("Mermaid");return o(),c("div",null,[e[1]||(e[1]=t('<h1 id="module-agent-tools" tabindex="-1">Module <code>agent:tools</code> <a class="header-anchor" href="#module-agent-tools" aria-label="Permalink to &quot;Module `agent:tools`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>The <code>agent:tools</code> module defines the tool system used by the agent to interact with and analyze C++ codebases. It owns a collection of concrete tool implementations—such as listing files, searching symbols, retrieving namespace contents, getting module or dependency information, and managing project guides—all registered in a static registry. The public interface centers on <code>build_tool_definitions</code> to populate the registry and <code>dispatch_tool_call</code> to execute a named tool with JSON arguments, returning either a string result or a <code>ToolError</code>. Supporting public types include <code>ToolError</code>, <code>ToolContext</code> (carrying project root, model, and output root), and the <code>ToolResultCache</code> for memoizing results. The module also exposes helper functions like <code>extract_string_arg</code> for argument validation and normalization utilities for guide filenames.</p><h2 id="imports" tabindex="-1">Imports <a class="header-anchor" href="#imports" aria-label="Permalink to &quot;Imports&quot;">​</a></h2><ul><li><a href="./../extract/"><code>extract</code></a></li><li><a href="./../generate/"><code>generate</code></a></li><li><a href="./../protocol/"><code>protocol</code></a></li><li><a href="./../schema/"><code>schema</code></a></li><li><code>std</code></li><li><a href="./../support/"><code>support</code></a></li></ul><h2 id="dependency-diagram" tabindex="-1">Dependency Diagram <a class="header-anchor" href="#dependency-diagram" aria-label="Permalink to &quot;Dependency Diagram&quot;">​</a></h2>',6)),(o(),l(u,null,{default:a(()=>[s(r,{id:"mermaid-47",class:"mermaid",graph:"graph%20LR%0A%20%20%20%20M0%5B%22agent%22%5D%0A%20%20%20%20I0%5B%22extract%22%5D%0A%20%20%20%20I0%20--%3E%20M0%0A%20%20%20%20I1%5B%22generate%22%5D%0A%20%20%20%20I1%20--%3E%20M0%0A%20%20%20%20I2%5B%22protocol%22%5D%0A%20%20%20%20I2%20--%3E%20M0%0A%20%20%20%20I3%5B%22schema%22%5D%0A%20%20%20%20I3%20--%3E%20M0%0A%20%20%20%20I4%5B%22support%22%5D%0A%20%20%20%20I4%20--%3E%20M0%0A"})]),fallback:a(()=>[...e[0]||(e[0]=[d(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=t('<h2 id="types" tabindex="-1">Types <a class="header-anchor" href="#types" aria-label="Permalink to &quot;Types&quot;">​</a></h2><h3 id="clore-agent-toolerror" tabindex="-1"><code>clore::agent::ToolError</code> <a class="header-anchor" href="#clore-agent-toolerror" aria-label="Permalink to &quot;`clore::agent::ToolError`&quot;">​</a></h3><p>Declaration: <code>agent/tools.cppm:16</code></p><p>Definition: <code>agent/tools.cppm:16</code></p><p>Declaration: <a href="./../../namespaces/clore/agent/"><code>Namespace clore::agent</code></a></p><p>The struct <code>clore::agent::ToolError</code> is a trivial error‑reporting type that holds a single <code>std::string</code> member named <code>message</code>. Its internal structure imposes no invariants beyond those inherent in <code>std::string</code>; the field is intended to carry a human‑readable description of an error condition that occurred during tool execution within the agent module. Because <code>ToolError</code> provides no custom constructors, assignment <code>operator</code>s, or other member functions, it relies entirely on the compiler‑generated defaults, making it a lightweight, value‑type wrapper around a diagnostic string.</p><h4 id="invariants" tabindex="-1">Invariants <a class="header-anchor" href="#invariants" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li>No explicit invariants beyond the presence of a message string.</li></ul><h4 id="key-members" tabindex="-1">Key Members <a class="header-anchor" href="#key-members" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li><code>std::string message</code></li></ul><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Returned or thrown by tool-related functions to indicate failure with a descriptive message.</li></ul><h2 id="variables" tabindex="-1">Variables <a class="header-anchor" href="#variables" aria-label="Permalink to &quot;Variables&quot;">​</a></h2><h3 id="arguments" tabindex="-1"><code>arguments</code> <a class="header-anchor" href="#arguments" aria-label="Permalink to &quot;`arguments`&quot;">​</a></h3><p>Declaration: <code>agent/tools.cppm:621</code></p><p>It serves as an input to the containing function, providing structured data that the function processes without modifying it.</p><h4 id="mutation" tabindex="-1">Mutation <a class="header-anchor" href="#mutation" aria-label="Permalink to &quot;Mutation&quot;">​</a></h4><p>No mutation is evident from the extracted code.</p><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>provides input data</li><li>read-only access</li></ul><h3 id="context" tabindex="-1"><code>context</code> <a class="header-anchor" href="#context" aria-label="Permalink to &quot;`context`&quot;">​</a></h3><p>Declaration: <code>agent/tools.cppm:621</code></p><p>It provides a read-only view of a <code>ToolContext</code> object, allowing access to context information without modification.</p><h4 id="mutation-1" tabindex="-1">Mutation <a class="header-anchor" href="#mutation-1" aria-label="Permalink to &quot;Mutation&quot;">​</a></h4><p>No mutation is evident from the extracted code.</p><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-agent-build-tool-definitions" tabindex="-1"><code>clore::agent::build_tool_definitions</code> <a class="header-anchor" href="#clore-agent-build-tool-definitions" aria-label="Permalink to &quot;`clore::agent::build_tool_definitions`&quot;">​</a></h3><p>Declaration: <code>agent/tools.cppm:23</code></p><p>Definition: <code>agent/tools.cppm:887</code></p><p>Declaration: <a href="./../../namespaces/clore/agent/"><code>Namespace clore::agent</code></a></p><p>The function <code>clore::agent::build_tool_definitions</code> begins by obtaining the static registry of tool specifications from <code>tool_registry()</code>, which returns a <code>const std::array&lt;ToolSpec, 12&gt;</code>. It reserves space in a local <code>std::vector&lt;clore::net::FunctionToolDefinition&gt;</code> for the expected number of definitions. The core loop iterates over each <code>ToolSpec</code> element in the registry and calls its <code>build_definition()</code> member. If any call returns a <code>std::expected</code> that does not contain a value, the function immediately returns <code>std::unexpected</code> with the moved <code>ToolError</code> from that failed attempt. Otherwise, the successfully built definition is moved into the output vector. After all tools are processed, the vector is returned on success.</p><p>This implementation has a single dependency on <code>tool_registry()</code> for enumerating the tools, and on each <code>ToolSpec</code>’s <code>build_definition()</code> to produce the corresponding <code>FunctionToolDefinition</code>. The algorithm is linear over the fixed set of twelve tool entries, with early termination on the first build failure. No caching or external state is involved beyond the registry.</p><h4 id="side-effects" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>tool_registry()</code> const array</li><li><code>ToolSpec</code> objects and their <code>build_definition()</code> method</li></ul><h4 id="usage-patterns-2" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-2" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Obtain tool definitions for sending to a language model</li><li>Called by agent initialization or tool call dispatch logic</li></ul><h3 id="clore-agent-dispatch-tool-call" tabindex="-1"><code>clore::agent::dispatch_tool_call</code> <a class="header-anchor" href="#clore-agent-dispatch-tool-call" aria-label="Permalink to &quot;`clore::agent::dispatch_tool_call`&quot;">​</a></h3><p>Declaration: <code>agent/tools.cppm:26</code></p><p>Definition: <code>agent/tools.cppm:902</code></p><p>Declaration: <a href="./../../namespaces/clore/agent/"><code>Namespace clore::agent</code></a></p><p>The function first serializes the JSON <code>arguments</code> into a string; if serialization fails it returns a <code>ToolError</code> with a formatted message. It then constructs a cache key as <code>&quot;{tool_name}:{serialized_arguments}&quot;</code> and consults a global <code>ToolResultCache</code> (obtained via <code>tool_result_cache()</code>) under a shared lock. If a cached result for that key exists, it is returned immediately, avoiding redundant computation. Otherwise, a <code>ToolContext</code> is assembled from the <code>model</code>, <code>project_root</code>, and <code>output_root</code> parameters. The function then iterates through the static tool registry (returned by <code>tool_registry()</code>) to find a <code>ToolSpec</code> whose <code>name</code> matches <code>tool_name</code>. For the matching tool, it delegates to that tool’s <code>dispatch</code> callable, passing the <code>arguments</code> and <code>context</code>. If the tool is marked <code>cacheable</code> and the dispatch succeeds, the result is stored in the cache under a unique lock before being returned. If no tool with the given name is found in the registry, the function returns a <code>ToolError</code> indicating an unknown tool.</p><h4 id="side-effects-1" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-1" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>updates the global tool result cache via <code>cache.result_by_key.insert_or_assign</code></li><li>acquires unique lock on cache mutex during cache write</li><li>dispatches tool call via <code>tool.dispatch</code> (tool-specific side effects unknown from evidence)</li></ul><h4 id="reads-from-1" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-1" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>parameter <code>tool_name</code></li><li>parameter <code>arguments</code></li><li>parameter <code>model</code></li><li>parameter <code>project_root</code></li><li>parameter <code>output_root</code></li><li>global <code>tool_result_cache()</code> (via shared lock)</li><li>global <code>tool_registry()</code></li><li>local <code>encoded_arguments</code></li><li>local <code>cache_key</code></li><li>cached result from <code>cache.result_by_key</code></li></ul><h4 id="writes-to" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li><code>cache.result_by_key</code> (map of cache key to result string)</li><li>cache mutex (unique lock acquisition)</li></ul><h4 id="usage-patterns-3" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-3" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>called to handle tool calls in agent execution loops</li><li>used by functions such as <code>run_agent_async</code> and <code>run_agent</code> to process tool dispatch requests</li></ul><h3 id="clore-agent-extract-string-arg" tabindex="-1"><code>clore::agent::extract_string_arg</code> <a class="header-anchor" href="#clore-agent-extract-string-arg" aria-label="Permalink to &quot;`clore::agent::extract_string_arg`&quot;">​</a></h3><p>Declaration: <code>agent/tools.cppm:20</code></p><p>Definition: <code>agent/tools.cppm:865</code></p><p>Declaration: <a href="./../../namespaces/clore/agent/"><code>Namespace clore::agent</code></a></p><p>The function <code>clore::agent::extract_string_arg</code> validates that the supplied <code>arguments</code> value is a JSON object; if not, it returns an error via <code>std::unexpected(ToolError{.message = &quot;arguments is not an object&quot;})</code>. It then dereferences the underlying object pointer (returning an error if the pointer is null) and performs a linear scan over the object’s entries. For each entry whose <code>key</code> matches the given <code>field_name</code>, it attempts to extract a string via <code>entry.value.get_string()</code>. On success the extracted string is returned; if the value is present but not a string, it yields a <code>ToolError</code> noting that the field is not a string. If no entry matches the field name, the function returns an error indicating the missing field. The error messages are formatted using <code>std::format</code> and packaged into <code>ToolError</code> structures. This function depends solely on the <code>json::Value</code> API (object checks, pointer retrieval, entry iteration) and the local <code>ToolError</code> type, with no reliance on any other part of the agent module.</p><h4 id="side-effects-2" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-2" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-2" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-2" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>arguments</code> parameter (<code>json::Value</code>&amp;)</li><li><code>field_name</code> parameter (<code>std::string_view</code>)</li></ul><h4 id="usage-patterns-4" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-4" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>used by <code>dispatch_tool_call</code> to extract string arguments from tool call argument objects</li></ul><h2 id="internal-structure" tabindex="-1">Internal Structure <a class="header-anchor" href="#internal-structure" aria-label="Permalink to &quot;Internal Structure&quot;">​</a></h2><p>The <code>agent:tools</code> module implements the tool-calling interface for the Clore agent, providing a set of individually defined tools that operate on project data managed by the <code>extract</code> and <code>generate</code> modules. It is structured around a common <code>ToolSpec</code> definition and a static registry built at startup via <code>build_tool_definitions</code>, which populates an <code>std::array</code> of tool specifications. Each tool, such as <code>ListFilesTool</code> or <code>SearchSymbolsTool</code>, is implemented as a struct with a <code>run</code> method and uses a template-based reflection mechanism (<code>dispatch_reflected_tool</code>, <code>make_tool_spec</code>) to automatically construct JSON schema definitions and argument parsing. The module imports <code>extract</code>, <code>generate</code>, <code>protocol</code>, <code>schema</code>, and <code>support</code> to access extracted symbol data, page generation helpers, LLM protocol types, JSON schema generation, and file system utilities.</p><p>Internally, a set of low-level helper functions (e.g., <code>tool_list_files</code>, <code>format_symbol_brief</code>, <code>tool_get_symbol</code>) encapsulate the core queries, while the <code>ToolResultCache</code> provides thread-safe caching of expensive operations. The public entry point <code>dispatch_tool_call</code> receives a tool name, JSON arguments, and a <code>ToolContext</code> (carrying project root, output root, model, etc.), routes to the correct tool, and returns either a string result or a <code>ToolError</code>.</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./../extract/">Module extract</a></li><li><a href="./../generate/">Module generate</a></li><li><a href="./../protocol/">Module protocol</a></li><li><a href="./../schema/">Module schema</a></li><li><a href="./../support/">Module support</a></li></ul>',67))])}const T=i(h,[["render",p]]);export{x as __pageData,T as default};
